{
  "$schema": "https://raw.githubusercontent.com/JanDeDobbeleer/oh-my-posh/main/themes/schema.json",
  "blocks": [
    {
      "type": "prompt",
      "alignment": "left",
      "segments": [
        {
          "properties": {
            "cache_duration": "none",
            "macos": "\uf179 ",
            "ubuntu": "\uf31b ",
            "windows": "\ue70f "
          },
          "leading_diamond": "\u256d\u2500\ue0b2",
          "template": " {{ .Icon }} ",
          "foreground": "#011627",
          "background": "#FEF5ED",
          "type": "os",
          "style": "diamond"
        },
        {
          "properties": {
            "cache_duration": "none"
          },
          "template": " \ue266 MEM:{{ round .PhysicalPercentUsed .Precision }}% [{{ (div ((sub .PhysicalTotalMemory .PhysicalAvailableMemory)|float64) 1073741824.0) }}/{{ (div .PhysicalTotalMemory 1073741824.0) }}GB] ",
          "foreground": "#FFFFFF",
          "powerline_symbol": "\ue0b0",
          "background": "#516BEB",
          "type": "sysinfo",
          "style": "powerline"
        },
        {
          "properties": {
            "cache_duration": "none"
          },
          "template": " \uf073 {{ .CurrentDate | date .Format }} ",
          "foreground": "#011627",
          "powerline_symbol": "\ue0b0",
          "background": "#FEF5ED",
          "type": "time",
          "style": "powerline"
        },
        {
          "properties": {
            "cache_duration": "none",
            "style": "roundrock",
            "threshold": 0
          },
          "template": " \uf2f2 {{ .FormattedMs }} ",
          "foreground": "#D6DEEB",
          "powerline_symbol": "\ue0b0",
          "background": "#575656",
          "type": "executiontime",
          "style": "powerline"
        }
      ],
      "newline": true
    },
    {
      "type": "prompt",
      "alignment": "left",
      "segments": [
        {
          "properties": {
            "cache_duration": "none",
            "folder_icon": "\uf07b",
            "home_icon": "home",
            "style": "agnoster_full"
          },
          "template": "\u2570\u2500\ue5ff {{.Path }}\uf101",
          "foreground": "#FEF5ED",
          "type": "path",
          "style": "diamond"
        }
      ],
      "newline": true
    }
  ],
  "version": 3,
  "final_space": true
}

{
  "version": "1.0.00001",
  "defaultLanguage": "en-us",
  "assets": [
    {
      "id": "864749",
      "type": "shortForm",
      "titles": [
        {
          "value": "Floating Time Screensaver",
          "languages": ["en-us"]
        }
      ],
      "shortDescriptions": [
        {
          "value": "A minimal floating clock screensaver displaying time and date on a black background.",
          "languages": ["en-us"]
        }
      ],
      "longDescriptions": [
        {
          "value": "Floating Time Screensaver displays the current time in 12-hour format with an optional date and seconds display. The clock gently floats across a black background to prevent screen burn-in. Configurable time zones, clock size, and display options.",
          "languages": ["en-us"]
        }
      ],
      "releaseDate": "2025-05-15",
      "releaseYear": 2025,
      "genres": ["entertainment"],
      "tags": ["screensaver", "clock", "time", "date", "utility"],
      "advisoryRatings": [
        {
          "source": "USA_PR",
          "value": "TV-G"
        }
      ],
      "images": [
        {
          "type": "main",
          "url": "https://drive.usercontent.google.com/u/1/uc?id=1DOaOHq55hwBH8z7-3rnaVqUXw2wUb73f&export=downloadh"
        }
      ],
      "content": {
        "playOptions": [
          {
            "license": "free",
            "quality": "fhd",
            "playId": "play-clock-screensaver-free",
            "availabilityInfo": {
              "country": ["us", "ca", "gb"]
            }
          }
        ]
      }
    }
  ]
}

